"use strict";(globalThis.webpackChunk_servicenow_sdk_docs=globalThis.webpackChunk_servicenow_sdk_docs||[]).push([[99569],{79717(e){e.exports=JSON.parse('{"tag":{"label":"ServicePortal","permalink":"/sdk/tags/service-portal","allTagsPath":"/sdk/tags","count":11,"items":[{"id":"api/service-portal/serviceportal-api","title":"Function: ServicePortal(config)","description":"Creates a Service Portal \u2014 a self-service web experience for end users built with AngularJS and Bootstrap 3 (sp_portal). Portals aggregate pages, widgets, themes, knowledge bases, and service catalogs into a branded, responsive interface.","permalink":"/sdk/api/service-portal/serviceportal-api"},{"id":"api/service-portal/spangularprovider-api","title":"Function: SPAngularProvider(config)","description":"Creates an AngularJS provider for Service Portal \u2014 a directive, factory, or service that extends widget functionality (spangularprovider). Providers are shared across widgets and enable reusable client-side logic.","permalink":"/sdk/api/service-portal/spangularprovider-api"},{"id":"api/service-portal/spheaderfooter-api","title":"Function: SPHeaderFooter(config)","description":"API used to create a Service Portal header or footer (spheaderfooter).","permalink":"/sdk/api/service-portal/spheaderfooter-api"},{"id":"api/service-portal/spmenu-api","title":"Function: SPMenu(config)","description":"Configures a Service Portal menu with hierarchical navigation items (spinstancemenu). Menus define the navigation structure within a portal, supporting page links, knowledge base links, catalog items, filtered lists, and scripted menu items.","permalink":"/sdk/api/service-portal/spmenu-api"},{"id":"api/service-portal/sppage-api","title":"Function: SPPage(config)","description":"Creates a Service Portal page \u2014 a layout of widget instances organized into containers, rows, and columns (sp_page). Pages are the top-level navigation targets in a portal and define the visual structure users interact with.","permalink":"/sdk/api/service-portal/sppage-api"},{"id":"api/service-portal/sppageroutemap-api","title":"Function: SPPageRouteMap(config)","description":"Creates a Service Portal page route map \u2014 a redirect rule that automatically routes users from one page to another within a portal (sppageroute_map). Route maps can be scoped to specific portals and roles, and support priority ordering when multiple rules match the same source page.","permalink":"/sdk/api/service-portal/sppageroutemap-api"},{"id":"api/service-portal/sptheme-api","title":"Function: SPTheme(config)","description":"API used to create a Service Portal theme (sp_theme).","permalink":"/sdk/api/service-portal/sptheme-api"},{"id":"api/service-portal/spwidget-api","title":"Function: SPWidget(config)","description":"Creates a Service Portal widget \u2014 a self-contained AngularJS component with its own server script, client controller, HTML template, and CSS (sp_widget). Widgets are the building blocks of Service Portal pages, handling data fetching, user interaction, and rendering.","permalink":"/sdk/api/service-portal/spwidget-api"},{"id":"api/service-portal/spwidgetdependency-api","title":"Function: SPWidgetDependency(config)","description":"Creates a widget dependency \u2014 a bundle of CSS and JavaScript includes that widgets and themes can reference (sp_dependency). Dependencies ensure that shared libraries and stylesheets are loaded when needed.","permalink":"/sdk/api/service-portal/spwidgetdependency-api"},{"id":"guides/atf-guide","title":"Implementing Tests Guide","description":"Create ServiceNow Automated Test Framework (ATF) test cases using Fluent APIs across 11 ATF categories: server, form, REST, catalog, email, app navigator, reporting, responsive dashboard, and Service Portal variants (formSP, catalogSP). This guide covers test strategy, category selection, step configuration, and the full API surface for each ATF namespace.","permalink":"/sdk/guides/atf-guide"},{"id":"guides/service-portal-guide","title":"Service Portal","description":"Guide for building ServiceNow Service Portal experiences using the Fluent API. Service Portal is a portal framework for building user-facing self-service experiences using AngularJS and Bootstrap 3. This guide covers core portal concepts: portals, pages, widgets, and themes.","permalink":"/sdk/guides/service-portal-guide"}],"unlisted":false}}')}}]);